package com.pos;
import javax.swing.*; import java.awt.*; import java.awt.event.*; import java.sql.*;
public class UserOrdersPanel extends JPanel {private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);public UserOrdersPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("My Orders and Receipts"),BorderLayout.WEST);JPanel p=new JPanel();JButton refresh=new JButton("Refresh"),orderOnline=new JButton("Order Online"),cancel=new JButton("Cancel Selected Pending Order");p.add(refresh);p.add(orderOnline);p.add(cancel);h.add(p,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);refresh.addActionListener(e->load());orderOnline.addActionListener(e->openOnlineOrderDialog());cancel.addActionListener(e->cancel());load();}
 // Open a dialog to browse products and place an online order. Refresh the order list when the dialog is closed.
 private void openOnlineOrderDialog(){JDialog dialog=new JDialog(SwingUtilities.getWindowAncestor(this),"Order Online",Dialog.ModalityType.APPLICATION_MODAL);dialog.setDefaultCloseOperation(WindowConstants.DISPOSE_ON_CLOSE);ProductBrowserPanel browser=new ProductBrowserPanel(s);dialog.add(browser);dialog.setSize(900,600);dialog.setLocationRelativeTo(this);dialog.addWindowListener(new WindowAdapter(){@Override public void windowClosed(WindowEvent e){load();}});dialog.setVisible(true);}
 private void load(){try{m.load("SELECT o.order_id,o.order_no,o.sale_type,o.subtotal,o.tax_amount,o.total_amount,o.amount_paid,o.balance,o.payment_status,o.order_status,r.receipt_no,o.created_at FROM sales_orders o LEFT JOIN sales_receipts r ON r.order_id=o.order_id JOIN customer_profiles cp ON cp.customer_id=o.customer_id WHERE cp.user_id=? ORDER BY o.order_id DESC",s.userId);}catch(Exception e){UIUtils.error(this,e);}}
 private void cancel(){int r=t.getSelectedRow();if(r<0)return;try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement("UPDATE sales_orders o JOIN customer_profiles cp ON cp.customer_id=o.customer_id SET o.order_status='CANCELLED' WHERE o.order_id=? AND cp.user_id=? AND o.order_status='PENDING' AND o.amount_paid=0")){p.setInt(1,Integer.parseInt(String.valueOf(t.getValueAt(t.convertRowIndexToModel(r),0))));p.setInt(2,s.userId);if(p.executeUpdate()==0)throw new SQLException("Only your unpaid pending order can be cancelled.");Audit.log(s,"CANCEL_ORDER","Customer cancelled pending order");load();}catch(Exception e){UIUtils.error(this,e);}}
}
